class Warlock:
    def __init__(self):
        self.spell_slots = {'max_level': True}  # All spell slots at max level
        self.needs_rest = False  # No rest required

    def cast_spell(self, spell_name):
        if self.spell_slots['max_level'] and not self.needs_rest:
            return f"Casting '{spell_name}' at max level!"
        else:
            return "Cannot cast spell: insufficient resources."

# Example usage
warlock = Warlock()
print(warlock.cast_spell("Astonishing New Project"))  # Output: Casting 'Astonishing New Project' at max level!
